import{_ as e,o,c as a,a2 as r}from"./chunks/framework.c3r8iWL8.js";const g=JSON.parse('{"title":"Guide: AI Coding Tools","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/ai-coding-tools.md","filePath":"guides/ai-coding-tools.md","lastUpdated":1782929962000}'),n={name:"guides/ai-coding-tools.md"};function d(i,t,s,l,c,p){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="guide-ai-coding-tools" tabindex="-1">Guide: AI Coding Tools <a class="header-anchor" href="#guide-ai-coding-tools" aria-label="Permalink to &quot;Guide: AI Coding Tools&quot;">​</a></h1><p><strong>Decision:</strong> Which AI-assisted development tools should the organization standardize on?</p><p><strong>Full catalog:</strong> <a href="./../ai-toolkit.html">AI toolkit</a> — all AI and AI-adjacent tools in one place.</p><p>Related: <a href="./../developer-workflow.html">developer-workflow.md</a> · <a href="./../sops/SOP-010-ai-tool-usage.html">SOP-010</a> · <a href="./ai-guardrails-security.html">ai-guardrails-security.md</a></p><hr><h2 id="options-compared" tabindex="-1">Options compared <a class="header-anchor" href="#options-compared" aria-label="Permalink to &quot;Options compared&quot;">​</a></h2><h3 id="cursor-ide-agents-mcp" tabindex="-1">Cursor (IDE + agents + MCP) <a class="header-anchor" href="#cursor-ide-agents-mcp" aria-label="Permalink to &quot;Cursor (IDE + agents + MCP)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>Deep codebase context, multi-file agents</td><td>Requires enterprise agreement for compliance</td></tr><tr><td>MCP integrates internal ADR/spec/runbook context</td><td>Team must govern <code>.cursor/rules</code> or agents drift</td></tr><tr><td>Best fit for &quot;vibe coding&quot; with steering</td><td>Another IDE to standardize if org is VS Code-only</td></tr></tbody></table><p><strong>Fit:</strong> Teams optimizing for AI-native velocity with spec/ADR context via MCP.</p><hr><h3 id="amazon-q-developer" tabindex="-1">Amazon Q Developer <a class="header-anchor" href="#amazon-q-developer" aria-label="Permalink to &quot;Amazon Q Developer&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>Native AWS/IaC guidance; enterprise boundary on AWS</td><td>Weaker general application refactoring vs Cursor</td></tr><tr><td>Fits AWS-heavy shops already on Q</td><td>Limited custom internal context without extra wiring</td></tr><tr><td>Good compliance story inside AWS accounts</td><td>Not a full replacement for IDE agent workflows</td></tr></tbody></table><p><strong>Fit:</strong> AWS-centric teams; IaC and service API work; complement to an IDE agent.</p><hr><h3 id="github-copilot" tabindex="-1">GitHub Copilot <a class="header-anchor" href="#github-copilot" aria-label="Permalink to &quot;GitHub Copilot&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>Broad adoption; familiar inline completion</td><td>Less agentic multi-step workflow than Cursor</td></tr><tr><td>Strong GitHub PR integration</td><td>MCP / deep monorepo context less mature than Cursor</td></tr><tr><td>Enterprise tier with policy controls</td><td>Competing agent story vs Copilot Workspace ( evolving )</td></tr></tbody></table><p><strong>Fit:</strong> GitHub-standard orgs wanting inline assist first; add agents later.</p><hr><h3 id="bedrock-agents-custom-planning-only" tabindex="-1">Bedrock agents (custom / planning-only) <a class="header-anchor" href="#bedrock-agents-custom-planning-only" aria-label="Permalink to &quot;Bedrock agents (custom / planning-only)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>Full control over prompts, RAG, and audit</td><td>Build and operate your own agent platform</td></tr><tr><td>VPC endpoints; no data leaves AWS</td><td>Higher platform engineering cost</td></tr><tr><td>Ideal for planning, ADR drafting, batch tasks</td><td>Poor DX if used as daily coding replacement</td></tr></tbody></table><p><strong>Fit:</strong> Platform team builds internal planning agents; not primary IDE.</p><hr><h3 id="local-models-ollama-etc" tabindex="-1">Local models (Ollama, etc.) <a class="header-anchor" href="#local-models-ollama-etc" aria-label="Permalink to &quot;Local models (Ollama, etc.)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>Offline; no cloud data transfer</td><td>Quality gap vs frontier models for complex code</td></tr><tr><td>Zero per-token cost</td><td>No enterprise support; security of local weights</td></tr><tr><td>Snippets and learning</td><td><strong>Do not use for proprietary codebase at scale</strong></td></tr></tbody></table><p><strong>Fit:</strong> Personal experimentation only — not enterprise default.</p><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><p><strong>Most enterprise AWS teams:</strong> Cursor (enterprise) for daily development + Amazon Q for AWS-specific work + Bedrock gateway for <strong>planning</strong> agents (ADR/spec draft). Document the combo in your ADR.</p><p>Avoid: letting every developer pick their own consumer AI tool without data policy.</p><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>No data classification policy</strong></td><td>PII or secrets in prompts → breach</td><td>SOP-style policy; block prod data; SEC review</td></tr><tr><td><strong>AI without spec/ADR context</strong></td><td>Hallucinated APIs, architecture drift</td><td>MCP or rules pointing at Approved specs + Accepted ADRs</td></tr><tr><td><strong>Treating AI output as trusted</strong></td><td>Bugs and security issues merge unchecked</td><td>Mandatory human PR review + automated scans</td></tr><tr><td><strong>Rules file neglect</strong></td><td>Agents ignore team conventions</td><td>Version <code>.cursor/rules</code> in Git; review in PRs</td></tr><tr><td><strong>Tool sprawl</strong></td><td>Inconsistent quality and audit</td><td>Pick primary + optional; exception process</td></tr><tr><td><strong>&quot;Vibe coding&quot; without contracts</strong></td><td>Fast today, untestable tomorrow</td><td>Spec-driven bounds (<a href="./spec-driven-development.html">spec-driven-development.md</a>)</td></tr><tr><td><strong>Skipping enterprise licenses</strong></td><td>Data used for training (consumer tiers)</td><td>Enterprise agreements with privacy guarantees</td></tr></tbody></table><hr><h2 id="related-decisions" tabindex="-1">Related decisions <a class="header-anchor" href="#related-decisions" aria-label="Permalink to &quot;Related decisions&quot;">​</a></h2><ul><li><a href="./knowledge-indexing-portals.html">Knowledge indexing</a> — how agents retrieve ADRs</li><li><a href="./ai-guardrails-security.html">AI guardrails</a> — what runs on every PR</li><li><a href="./human-in-the-loop-governance.html">Human-in-the-loop</a> — who approves what AI cannot</li></ul>',35)])])}const u=e(n,[["render",d]]);export{g as __pageData,u as default};
